   */
  record(params: {
    metadata: Omit<VisionMetadata, 'capturedAt' | 'sessionId'>;
    perception: PerceptionSnapshot;
    reflection: ReflectionLayer;
    imageDataUri?: string;
    previousVisionId?: string;
