      params.imageDataUri,
      params.previousVisionId
    );

    if (params.themeTag) {
      entry.continuity = {
        ...entry.continuity,
        themeTag: params.themeTag,
      };
    }

    saveEntry(entry);
    return entry;
  },

  /**
   * Find entry by ID
