console.log('Captured:', entry.metadata.capturedAt);
console.log('');
console.log('Elements:', entry.perception.elements.join(', '));
console.log('Lens:', entry.perception.lens);
console.log('Theme:', entry.continuity?.themeTag);
console.log('');

const stats = VisionJournal.getStats();
console.log('=== Statistics ===');
console.log(`Total entries: ${stats.totalEntries}`);
console.log(`Self-revelations: ${stats.selfRevelationsCount}`);
console.log(`Pattern connections: ${stats.patternConnections}`);

const patterns = VisionJournal.analyzePatterns();
console.log('\n=== Recurring Patterns ===');
patterns.slice(0, 5).forEach(p => {
  console.log(`- ${p.pattern}: ${p.frequency}x (${p.significance})`);
});
